const items = $input.all();
const today = new Date().toISOString().split('T')[0];

if (items.length === 0) {
  return [{ json: { message: '*Daily Churn Report -- ' + today + '*\n\nNo churned accounts found in the last 30 days.' } }];
}

const totalMRR = items.reduce(function(sum, i) {
  return sum + (parseFloat(i.json.churn_mrr) || 0);
}, 0);

const lines = items.map(function(i) {
  const d = i.json;
  const mrr = d.churn_mrr ? '$' + Math.round(parseFloat(d.churn_mrr)).toLocaleString('en-US') : 'N/A';
  const etf = d.etf ? ' | ETF: ' + d.etf : '';
  return '- *' + (d.account_name || 'Unknown') + '* | Owner: ' + (d.account_owner || 'N/A') + ' | CSM: ' + (d.csm || 'N/A') + ' | MRR: ' + mrr + ' | Reason: ' + (d.churn_reason || 'N/A') + ' | Type: ' + (d.churn_type || 'N/A') + ' | Segment: ' + (d.account_segmentation || 'N/A') + ' | Geo: ' + (d.geo_area || 'N/A') + etf;
});

const header = '*Daily Churn Report -- ' + today + '*\n*' + items.length + ' account(s) churned in the last 30 days | Total Churn MRR: $' + Math.round(totalMRR).toLocaleString('en-US') + '*';

const message = header + '\n\n' + lines.join('\n');

return [{ json: { message: message } }];
